from collections import deque

def digit_length(x):
    return len(str(x))

def solve():
    n, x = map(int, input().split())
    visited = set()
    queue = deque()
    queue.append((x, 0))
    visited.add(x)

    while queue:
        current, steps = queue.popleft()
        current_len = digit_length(current)
        if current_len == n:
            print(steps)
            return
        if current_len > n:
            continue
        digits = set(str(current))
        for d in digits:
            d_int = int(d)
            if d_int <= 1:
                continue
            next_num = current * d_int
            if next_num not in visited:
                visited.add(next_num)
                queue.append((next_num, steps + 1))
    print(-1)

solve()
